import azure.functions as func
import json
import logging

app = func.FunctionApp()

@app.route(route="http_trigger", methods=["GET", "POST"])
@app.queue_output(arg_name="msg", queue_name="output-queue", connection="AzureWebJobsStorage")
def http_trigger(req: func.HttpRequest, msg: func.QueueMessage) -> func.HttpResponse:
    logging.info('Python HTTP trigger function processed a request.')

    # Get request body
    try:
        req_body = req.get_json()
    except ValueError:
        req_body = None

    name = req_body.get('name') if req_body else None

    if name:
        # Prepare message for queue
        message = f"Hello, {name}! Your request has been processed."
        msg.set(message)

        return func.HttpResponse(
            json.dumps({"status": "success", "message": message}),
            mimetype="application/json",
            status_code=200
        )
    else:
        return func.HttpResponse(
            json.dumps({"status": "error", "message": "Please provide a 'name' in request body"}),
            mimetype="application/json",
            status_code=400
        )

